import requests
import json
from uuid import uuid4

def test_procedure_record_with_valid_encounter(base_url='http://localhost:8000'):
    encounter_id = str(uuid4())
    encounter_ref = f'Encounter/{encounter_id}'
    procedure_payload = {
        'resourceType': 'Procedure',
        'status': 'completed',
        'code': {
            'coding': [{
                'system': 'http://snomed.info/sct',
                'code': '80146002',
                'display': 'Examination of heart'
            }]
        },
        'subject': {'reference': f'Patient/{uuid4()}'},
        'encounter': {'reference': encounter_ref},
        'performedDateTime': '2024-01-15T10:00:00Z'
    }
    resp = requests.post(
        f'{base_url}/Procedure',
        json=procedure_payload,
        headers={'Content-Type': 'application/fhir+json'}
    )
    assert resp.status_code in [200, 201], f'Status {resp.status_code}: {resp.text}'
    body = resp.json()
    assert body.get('resourceType') == 'Procedure'
    assert body.get('id') is not None
    assert body['encounter']['reference'] == encounter_ref

