def test_procedure_record_missing_encounter_returns_422(base_url='http://localhost:8000'):
    procedure_payload = {
        'resourceType': 'Procedure',
        'status': 'completed',
        'code': {
            'coding': [{
                'system': 'http://snomed.info/sct',
                'code': '80146002'
            }]
        },
        'subject': {'reference': f'Patient/{uuid4()}'}
    }
    resp = requests.post(
        f'{base_url}/Procedure',
        json=procedure_payload,
        headers={'Content-Type': 'application/fhir+json'}
    )
    assert resp.status_code == 422, f'Expected 422, got {resp.status_code}'
    body = resp.json()
    assert body.get('resourceType') == 'OperationOutcome'
    assert len(body.get('issue', [])) > 0

